-- math: Exponent Rules
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Exponent Rules", "body": "Use the laws of exponents to multiply, divide, and raise powers to powers."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Simplify and evaluate:  2^1 x 2^1 = ?\n\nThe answer is \"4\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Simplify and evaluate:  3^3 / 3^2 = ?\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Simplify and evaluate:  (2^2)^3 = ?\n\nThe answer is \"64\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Simplify and evaluate:  3^4 / 3^3 = ?\n\nThe answer is 3."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Simplify and evaluate:  (4^3)^2 = ?\n\nThe answer is 4096."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Simplify and evaluate:  2^5 / 2^4 = ?\n\nThe answer is 2."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Exponent Rules! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$exponent-rules$tl$ and t.grade_level = 8);

-- math: Scientific Notation
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Scientific Notation", "body": "Scientific notation writes very large or small numbers as a number times a power of ten."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Write 3.2 x 10^2 as a standard number (no commas).\n\nThe answer is \"320\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Write 7.2 x 10^2 as a standard number (no commas).\n\nThe answer is \"720\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Write 5.2 x 10^2 as a standard number (no commas).\n\nThe answer is \"520\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Write 9.7 x 10^3 as a standard number (no commas).\n\nThe answer is 9700."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Write 2.7 x 10^3 as a standard number (no commas).\n\nThe answer is 2700."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Write 3.6 x 10^3 as a standard number (no commas).\n\nThe answer is 3600."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Scientific Notation! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$scientific-notation$tl$ and t.grade_level = 8);

-- math: Square & Cube Roots
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Square & Cube Roots", "body": "A square root undoes squaring; a cube root undoes cubing."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the square root of 25?\n\nThe answer is \"5\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the square root of 9?\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the square root of 64?\n\nThe answer is \"8\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the square root of 324?\n\nThe answer is 18."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the square root of 144?\n\nThe answer is 12."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the square root of 256?\n\nThe answer is 16."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Square & Cube Roots! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$roots$tl$ and t.grade_level = 8);

-- math: Linear Equations
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Linear Equations", "body": "Solve equations with variables on both sides by collecting like terms."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Solve for x:  3x + 1 = 1x + 13\n\nThe answer is \"6\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Solve for x:  4x + 3 = 3x + 10\n\nThe answer is \"7\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Solve for x:  4x + 7 = 3x + 9\n\nThe answer is \"2\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Solve for x:  4x + 5 = 2x + 17\n\nThe answer is 6."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Solve for x:  7x + 10 = 1x + 52\n\nThe answer is 7."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Solve for x:  3x + 12 = 2x + 18\n\nThe answer is 6."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Linear Equations! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$linear-equations$tl$ and t.grade_level = 8);

-- math: Slope
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Slope", "body": "Slope is the rate of change: the rise (change in y) divided by the run (change in x)."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Find the slope of the line through (3, 2) and (6, 11).\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Find the slope of the line through (4, 6) and (5, 9).\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Find the slope of the line through (3, 4) and (7, 20).\n\nThe answer is \"4\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Find the slope of the line through (5, 6) and (9, 26).\n\nThe answer is 5."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Find the slope of the line through (5, 2) and (9, 14).\n\nThe answer is 3."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Find the slope of the line through (4, 3) and (9, 28).\n\nThe answer is 5."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Slope! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$slope$tl$ and t.grade_level = 8);

-- math: Pythagorean Theorem
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Pythagorean Theorem", "body": "In a right triangle, a^2 + b^2 = c^2, where c is the hypotenuse."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A right triangle has legs of 6 and 8. What is the length of the hypotenuse?\n\nThe answer is \"10\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A right triangle has legs of 8 and 15. What is the length of the hypotenuse?\n\nThe answer is \"17\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A right triangle has legs of 3 and 4. What is the length of the hypotenuse?\n\nThe answer is \"5\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  A right triangle has a hypotenuse of 25 and one leg of 7. What is the other leg?\n\nThe answer is 24."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  A right triangle has a hypotenuse of 10 and one leg of 6. What is the other leg?\n\nThe answer is 8."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  A right triangle has a hypotenuse of 15 and one leg of 9. What is the other leg?\n\nThe answer is 12."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Pythagorean Theorem! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$pythagorean-theorem$tl$ and t.grade_level = 8);

-- math: Functions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Functions", "body": "A function pairs each input with exactly one output. Evaluate f(x) by substituting."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  If f(x) = 5x + 2, what is f(3)?\n\nThe answer is \"17\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  If f(x) = 5x + 6, what is f(6)?\n\nThe answer is \"36\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  If f(x) = 5x + 7, what is f(3)?\n\nThe answer is \"22\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  If f(x) = 3x + 5, what is f(8)?\n\nThe answer is 29."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  If f(x) = 4x + 1, what is f(6)?\n\nThe answer is 25."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  If f(x) = 3x + 2, what is f(8)?\n\nThe answer is 26."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Functions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$functions$tl$ and t.grade_level = 8);

