-- math: Rational & Irrational Numbers
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Rational & Irrational Numbers", "body": "Rational numbers can be written as fractions; irrational numbers (like pi) cannot."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Is the number 5 rational or irrational?\n\nThe answer is \"rational\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Is the decimal 0.1010010001... (never repeats) rational or irrational?\n\nThe answer is \"irrational\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Is the square root of 5 rational or irrational?\n\nThe answer is \"irrational\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Is the fraction 2/7 rational or irrational?", "choices": [{"id": "a", "label": "irrational"}, {"id": "b", "label": "both"}, {"id": "c", "label": "rational"}, {"id": "d", "label": "neither"}], "answer": "c", "explanation": "Yes! The answer is \"rational\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Is the square root of 20 rational or irrational?", "choices": [{"id": "a", "label": "rational"}, {"id": "b", "label": "both"}, {"id": "c", "label": "neither"}, {"id": "d", "label": "irrational"}], "answer": "d", "explanation": "Yes! The answer is \"irrational\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Is the number pi rational or irrational?", "choices": [{"id": "a", "label": "rational"}, {"id": "b", "label": "irrational"}, {"id": "c", "label": "both"}, {"id": "d", "label": "neither"}], "answer": "b", "explanation": "Yes! The answer is \"irrational\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Rational & Irrational Numbers! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
