  where s.slug = $tl$math$tl$ and t.slug = $tl$rational-irrational$tl$ and t.grade_level = 8);

-- math: Slope-Intercept Form
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Slope-Intercept Form", "body": "In y = mx + b, m is the slope and b is the y-intercept."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  For the line y = 3x + 5, what is the slope?\n\nThe answer is \"3\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  For the line y = 5x + 1, what is the y-intercept?\n\nThe answer is \"1\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  For the line y = 5x + 3, what is the slope?\n\nThe answer is \"5\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  For the line y = 7x + 4, what is the slope?\n\nThe answer is 7."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  For the line y = 6x + 3, what is the y-intercept?\n\nThe answer is 3."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  For the line y = 3x + 1, what is the y-intercept?\n\nThe answer is 1."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Slope-Intercept Form! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$math$tl$ and t.slug = $tl$slope-intercept$tl$ and t.grade_level = 8);

