update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Forces & Motion", "body": "Newton's laws and graphs describe how forces change an object's motion."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Newton's second law is written as the equation:\n\nThe answer is \"F = ma\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  If the net force on an object is zero, its velocity is:\n\nThe answer is \"constant (unchanging)\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A 2 kg object accelerating at 3 m/s^2 experiences a net force of:\n\nThe answer is \"6 N\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Acceleration is the rate of change of:", "choices": [{"id": "a", "label": "velocity"}, {"id": "b", "label": "mass"}, {"id": "c", "label": "force"}, {"id": "d", "label": "distance"}], "answer": "a", "explanation": "Yes! The answer is \"velocity\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "On a distance-time graph, a steeper line means a:", "choices": [{"id": "a", "label": "slower speed"}, {"id": "b", "label": "object at rest"}, {"id": "c", "label": "negative mass"}, {"id": "d", "label": "greater speed"}], "answer": "d", "explanation": "Yes! The answer is \"greater speed\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A flat (horizontal) line on a distance-time graph means the object is:", "choices": [{"id": "a", "label": "speeding up"}, {"id": "b", "label": "at rest"}, {"id": "c", "label": "slowing down"}, {"id": "d", "label": "moving fastest"}], "answer": "b", "explanation": "Yes! The answer is \"at rest\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Forces & Motion! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$science$tl$ and t.slug = $tl$forces-and-motion$tl$ and t.grade_level = 8);

-- science: Energy & Its Conservation
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Energy & Its Conservation", "body": "Energy changes form and is conserved; work transfers energy to objects."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Kinetic energy depends on an object's mass and its:\n\nThe answer is \"speed (velocity)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Gravitational potential energy depends on mass, gravity, and:\n\nThe answer is \"height\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The law of conservation of energy says energy is:\n\nThe answer is \"never created or destroyed\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "As a roller coaster descends, potential energy transforms into:", "choices": [{"id": "a", "label": "chemical energy"}, {"id": "b", "label": "mass"}, {"id": "c", "label": "kinetic energy"}, {"id": "d", "label": "sound only"}], "answer": "c", "explanation": "Yes! The answer is \"kinetic energy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Doing work on an object transfers ____ to it.", "choices": [{"id": "a", "label": "mass"}, {"id": "b", "label": "color"}, {"id": "c", "label": "charge"}, {"id": "d", "label": "energy"}], "answer": "d", "explanation": "Yes! The answer is \"energy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The SI unit of energy and work is the:", "choices": [{"id": "a", "label": "newton"}, {"id": "b", "label": "watt"}, {"id": "c", "label": "joule"}, {"id": "d", "label": "meter"}], "answer": "c", "explanation": "Yes! The answer is \"joule\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Energy & Its Conservation! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
