-- science: Chemical Reactions
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Chemical Reactions", "body": "Reactions rearrange atoms and conserve mass; bonds form by sharing or transferring electrons."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  In a chemical reaction, atoms are:\n\nThe answer is \"rearranged, not created or destroyed\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A balanced equation has equal numbers of each atom on:\n\nThe answer is \"both sides\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  The principle that mass is the same before and after a reaction is:\n\nThe answer is \"conservation of mass\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Evidence of a chemical reaction can include a color change, gas, or:", "choices": [{"id": "a", "label": "a change in shape only"}, {"id": "b", "label": "melting only"}, {"id": "c", "label": "dissolving only"}, {"id": "d", "label": "temperature change"}], "answer": "d", "explanation": "Yes! The answer is \"temperature change\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A reaction that releases energy (heat) is:", "choices": [{"id": "a", "label": "endothermic"}, {"id": "b", "label": "physical"}, {"id": "c", "label": "neutral"}, {"id": "d", "label": "exothermic"}], "answer": "d", "explanation": "Yes! The answer is \"exothermic\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A reaction that absorbs energy is:", "choices": [{"id": "a", "label": "exothermic"}, {"id": "b", "label": "physical"}, {"id": "c", "label": "endothermic"}, {"id": "d", "label": "instant"}], "answer": "c", "explanation": "Yes! The answer is \"endothermic\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Chemical Reactions! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
