update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Atoms & the Periodic Table", "body": "Atomic structure and the periodic table explain elements' properties and reactivity."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The number of protons in an atom defines its:\n\nThe answer is \"element (atomic number)\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Atoms of the same element with different neutron counts are:\n\nThe answer is \"isotopes\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An atom that has lost or gained electrons is an:\n\nThe answer is \"ion\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Vertical columns of the periodic table are:", "choices": [{"id": "a", "label": "periods"}, {"id": "b", "label": "rows only"}, {"id": "c", "label": "groups (families)"}, {"id": "d", "label": "cells"}], "answer": "c", "explanation": "Yes! The answer is \"groups (families)\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Elements in the same group tend to have similar:", "choices": [{"id": "a", "label": "masses exactly"}, {"id": "b", "label": "colors"}, {"id": "c", "label": "prices"}, {"id": "d", "label": "chemical properties"}], "answer": "d", "explanation": "Yes! The answer is \"chemical properties\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Across a period, atomic number ____ from left to right.", "choices": [{"id": "a", "label": "decreases"}, {"id": "b", "label": "increases"}, {"id": "c", "label": "stays the same"}, {"id": "d", "label": "is random"}], "answer": "b", "explanation": "Yes! The answer is \"increases\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Atoms & the Periodic Table! Now tap a worksheet to practice and earn points. You can always come back to 