-- science: Evolution & Natural Selection
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Evolution & Natural Selection", "body": "Natural selection, supported by fossil, anatomical, and DNA evidence, shapes species over time."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Heritable traits that improve survival and reproduction tend to become:\n\nThe answer is \"more common over generations\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  The raw material for new variation in populations comes from:\n\nThe answer is \"mutations\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An organism's reproductive success is a measure of its:\n\nThe answer is \"fitness\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Natural selection requires variation, heredity, and differences in:", "choices": [{"id": "a", "label": "survival and reproduction"}, {"id": "b", "label": "color only"}, {"id": "c", "label": "names"}, {"id": "d", "label": "habitats only"}], "answer": "a", "explanation": "Yes! The answer is \"survival and reproduction\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Fossils, anatomy, and DNA all provide ____ for evolution.", "choices": [{"id": "a", "label": "disproof"}, {"id": "b", "label": "evidence"}, {"id": "c", "label": "randomness"}, {"id": "d", "label": "opinions"}], "answer": "b", "explanation": "Yes! The answer is \"evidence\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Over very long times, accumulated changes can produce new:", "choices": [{"id": "a", "label": "planets"}, {"id": "b", "label": "minerals"}, {"id": "c", "label": "seasons"}, {"id": "d", "label": "species"}], "answer": "d", "explanation": "Yes! The answer is \"species\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Evolution & Natural Selection! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
