update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Genetics & Heredity", "body": "Genes made of DNA pass traits to offspring; mutations create variation."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Genes are segments of:\n\nThe answer is \"DNA\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Different versions of the same gene are called:\n\nThe answer is \"alleles\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  An organism's genetic makeup is its:\n\nThe answer is \"genotype\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An organism's observable traits make up its:", "choices": [{"id": "a", "label": "genotype"}, {"id": "b", "label": "phenotype"}, {"id": "c", "label": "allele"}, {"id": "d", "label": "gene"}], "answer": "b", "explanation": "Yes! The answer is \"phenotype\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A capital letter usually represents a ____ allele.", "choices": [{"id": "a", "label": "recessive"}, {"id": "b", "label": "mutated"}, {"id": "c", "label": "dominant"}, {"id": "d", "label": "missing"}], "answer": "c", "explanation": "Yes! The answer is \"dominant\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A trait expressed only when two recessive alleles are present is:", "choices": [{"id": "a", "label": "dominant"}, {"id": "b", "label": "codominant always"}, {"id": "c", "label": "recessive"}, {"id": "d", "label": "blended"}], "answer": "c", "explanation": "Yes! The answer is \"recessive\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Genetics & Heredity! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
