update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Gravity & the Solar System", "body": "Gravity governs orbits, tides, eclipses, and the motions of the solar system."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  The force that keeps planets in orbit around the Sun is:\n\nThe answer is \"gravity\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Gravitational force between two objects increases with greater ____ and less distance.\n\nThe answer is \"mass\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Earth's seasons are caused by the:\n\nThe answer is \"tilt of Earth's axis as it orbits\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A solar eclipse occurs when the ____ blocks sunlight to Earth.", "choices": [{"id": "a", "label": "Sun"}, {"id": "b", "label": "Moon"}, {"id": "c", "label": "another planet"}, {"id": "d", "label": "a comet"}], "answer": "b", "explanation": "Yes! The answer is \"Moon\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A lunar eclipse occurs when ____ shadow falls on the Moon.", "choices": [{"id": "a", "label": "Earth's"}, {"id": "b", "label": "the Sun's"}, {"id": "c", "label": "Mars's"}, {"id": "d", "label": "Jupiter's"}], "answer": "a", "explanation": "Yes! The answer is \"Earth's\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "The Moon shines because it ____ sunlight.", "choices": [{"id": "a", "label": "produces"}, {"id": "b", "label": "reflects"}, {"id": "c", "label": "absorbs all"}, {"id": "d", "label": "blocks"}], "answer": "b", "explanation": "Yes! The answer is \"reflects\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Gravity & the Solar System! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$t