update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Plate Tectonics", "body": "Moving plates, driven by mantle convection, reshape Earth and cause quakes and volcanoes."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Earth's lithosphere is broken into moving:\n\nThe answer is \"tectonic plates\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Plates move because of ____ currents in the mantle.\n\nThe answer is \"convection\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  At a divergent boundary, plates:\n\nThe answer is \"move apart, forming new crust\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "At a convergent boundary, plates:", "choices": [{"id": "a", "label": "spread apart"}, {"id": "b", "label": "slide past only"}, {"id": "c", "label": "vanish"}, {"id": "d", "label": "collide"}], "answer": "d", "explanation": "Yes! The answer is \"collide\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "At a transform boundary, plates:", "choices": [{"id": "a", "label": "collide head-on"}, {"id": "b", "label": "spread apart"}, {"id": "c", "label": "melt"}, {"id": "d", "label": "slide past each other"}], "answer": "d", "explanation": "Yes! The answer is \"slide past each other\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Most earthquakes and volcanoes occur:", "choices": [{"id": "a", "label": "along plate boundaries"}, {"id": "b", "label": "randomly anywhere"}, {"id": "c", "label": "in the sky"}, {"id": "d", "label": "only midplate"}], "answer": "a", "explanation": "Yes! The answer is \"along plate boundaries\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Plate Tectonics! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
