update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Central Idea & Analysis", "body": "Determine central ideas and analyze how they develop through supporting details."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A central idea is best described as a text's:\n\nThe answer is \"most important controlling point\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Two or more central ideas in a longer text are usually connected by a:\n\nThe answer is \"shared overall message or topic\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Read: \"Automation boosts productivity but also displaces some workers, forcing society to adapt.\" The central idea is that automation:\n\nThe answer is \"brings both gains and challenges\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Supporting details strengthen a central idea by providing:", "choices": [{"id": "a", "label": "evidence and examples"}, {"id": "b", "label": "distractions"}, {"id": "c", "label": "the title"}, {"id": "d", "label": "page numbers"}], "answer": "a", "explanation": "Yes! The answer is \"evidence and examples\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To analyze how a central idea develops, trace it across:", "choices": [{"id": "a", "label": "a single word"}, {"id": "b", "label": "paragraphs and sections"}, {"id": "c", "label": "the cover"}, {"id": "d", "label": "the index"}], "answer": "b", "explanation": "Yes! The answer is \"paragraphs and sections\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "An objective statement of a central idea omits the reader's:", "choices": [{"id": "a", "label": "the main point"}, {"id": "b", "label": "key evidence"}, {"id": "c", "label": "topic"}, {"id": "d", "label": "personal judgments"}], "answer": "d", "explanation": "Yes! The answer is \"personal judgments\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Central Idea & Analysis! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
