update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Theme Development", "body": "Analyze how a theme develops over the course of a text through plot and character."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A theme is a literary work's:\n\nThe answer is \"central message about life or human nature\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Authors develop a theme through plot, conflict, and:\n\nThe answer is \"characters' choices and changes\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A theme differs from a subject because a theme is a:\n\nThe answer is \"complete insight or claim\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"Warned of the danger, the leaders ignored it and the city fell.\" A theme is:", "choices": [{"id": "a", "label": "ignoring wisdom invites disaster"}, {"id": "b", "label": "cities are old"}, {"id": "c", "label": "warnings are fun"}, {"id": "d", "label": "leaders are tall"}], "answer": "a", "explanation": "Yes! The answer is \"ignoring wisdom invites disaster\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A recurring symbol throughout a story often reinforces the:", "choices": [{"id": "a", "label": "index"}, {"id": "b", "label": "theme"}, {"id": "c", "label": "page count"}, {"id": "d", "label": "glossary"}], "answer": "b", "explanation": "Yes! The answer is \"theme\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To analyze theme development, track how it emerges:", "choices": [{"id": "a", "label": "only at the start"}, {"id": "b", "label": "in the title only"}, {"id": "c", "label": "over the entire text"}, {"id": "d", "label": "never"}], "answer": "c", "explanation": "Yes! The answer is \"over the entire text\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Theme Development! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
