update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Objective Summary", "body": "Summarize a text's central ideas and key details objectively."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An objective summary remains:\n\nThe answer is \"neutral and free of personal opinion\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A strong summary captures the central idea and the:\n\nThe answer is \"most significant supporting details\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A summary should be ____ than the original text.\n\nThe answer is \"more concise\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Summaries should be written in:", "choices": [{"id": "a", "label": "the author's exact words"}, {"id": "b", "label": "code"}, {"id": "c", "label": "the reader's own words"}, {"id": "d", "label": "emojis"}], "answer": "c", "explanation": "Yes! The answer is \"the reader's own words\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "What does NOT belong in an objective summary?", "choices": [{"id": "a", "label": "the central idea"}, {"id": "b", "label": "the reader's evaluation"}, {"id": "c", "label": "key points"}, {"id": "d", "label": "the topic"}], "answer": "b", "explanation": "Yes! The answer is \"the reader's evaluation\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "In summarizing an argument, include the author's claim and:", "choices": [{"id": "a", "label": "favorite color"}, {"id": "b", "label": "main supporting reasons"}, {"id": "c", "label": "birthday"}, {"id": "d", "label": "font"}], "answer": "b", "explanation": "Yes! The answer is \"main supporting reasons\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Objective Summary! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
