update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Author's Purpose & Rhetoric", "body": "Analyze an author's purpose, perspective, and use of rhetorical appeals."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  An author's purpose could be to inform, entertain, persuade, or:\n\nThe answer is \"explain a process\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  An author's perspective is their:\n\nThe answer is \"stance or attitude toward the topic\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  A persuasive essay primarily aims to:\n\nThe answer is \"convince the reader\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Emotionally charged word choice can reveal an author's:", "choices": [{"id": "a", "label": "page number"}, {"id": "b", "label": "font"}, {"id": "c", "label": "bias / perspective"}, {"id": "d", "label": "binding"}], "answer": "c", "explanation": "Yes! The answer is \"bias / perspective\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A text presenting only one side of an issue is likely:", "choices": [{"id": "a", "label": "objective"}, {"id": "b", "label": "fictional"}, {"id": "c", "label": "biased"}, {"id": "d", "label": "a poem"}], "answer": "c", "explanation": "Yes! The answer is \"biased\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "To find the author's purpose, ask:", "choices": [{"id": "a", "label": "why was this written?"}, {"id": "b", "label": "how long is it?"}, {"id": "c", "label": "who printed it?"}, {"id": "d", "label": "what font?"}], "answer": "a", "explanation": "Yes! The answer is \"why was this written?\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Author's Purpose & Rhetoric! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
