update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Word Meaning & Connotation", "body": "Analyze denotation, connotation, roots, and affixes to determine meaning."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  A word's denotation is its:\n\nThe answer is \"literal dictionary meaning\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A word's connotation is its:\n\nThe answer is \"emotional or implied association\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  'Frugal' and 'stingy' share a denotation but differ in:\n\nThe answer is \"connotation\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which has the more POSITIVE connotation?", "choices": [{"id": "a", "label": "arrogant"}, {"id": "b", "label": "confident"}, {"id": "c", "label": "cocky"}, {"id": "d", "label": "smug"}], "answer": "b", "explanation": "Yes! The answer is \"confident\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Which has the more NEGATIVE connotation?", "choices": [{"id": "a", "label": "curious"}, {"id": "b", "label": "interested"}, {"id": "c", "label": "inquisitive"}, {"id": "d", "label": "nosy"}], "answer": "d", "explanation": "Yes! The answer is \"nosy\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Read: \"A delicate aroma drifted from the kitchen.\" \"Aroma\" carries a ____ connotation.", "choices": [{"id": "a", "label": "negative"}, {"id": "b", "label": "positive"}, {"id": "c", "label": "strictly neutral"}, {"id": "d", "label": "no"}], "answer": "b", "explanation": "Yes! The answer is \"positive\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Word Meaning & Connotation! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
