update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Figurative Language & Tone", "body": "Interpret figurative language and analyze how word choice creates tone and mood."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  \"The news was a punch to the gut\" is a:\n\nThe answer is \"metaphor\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  \"She fought like a tiger\" is a:\n\nThe answer is \"simile\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Giving human qualities to nonhuman things is:\n\nThe answer is \"personification\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "\"I'm so hungry I could eat a horse\" is:", "choices": [{"id": "a", "label": "a simile"}, {"id": "b", "label": "hyperbole"}, {"id": "c", "label": "a metaphor"}, {"id": "d", "label": "an idiom"}], "answer": "b", "explanation": "Yes! The answer is \"hyperbole\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "'Bite the bullet,' meaning to endure hardship, is an:", "choices": [{"id": "a", "label": "idiom"}, {"id": "b", "label": "literal action"}, {"id": "c", "label": "simile"}, {"id": "d", "label": "fact"}], "answer": "a", "explanation": "Yes! The answer is \"idiom\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Tone is the author's ____ toward the subject.", "choices": [{"id": "a", "label": "attitude"}, {"id": "b", "label": "page count"}, {"id": "c", "label": "font"}, {"id": "d", "label": "spelling"}], "answer": "a", "explanation": "Yes! The answer is \"attitude\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Figurative Language & Tone! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
