update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Analyzing Conflicting Sources", "body": "Analyze how two texts present and interpret the same topic or event differently."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Comparing two texts on the same topic highlights their differing:\n\nThe answer is \"approaches and perspectives\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  A firsthand memoir and a researched article on one event differ most in:\n\nThe answer is \"point of view and type of detail\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  When two authors disagree, a critical reader:\n\nThe answer is \"weighs the evidence and reasoning in each\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "Reading several sources on a topic helps a reader develop a:", "choices": [{"id": "a", "label": "more balanced, informed view"}, {"id": "b", "label": "narrower view"}, {"id": "c", "label": "less knowledge"}, {"id": "d", "label": "ignorance of facts"}], "answer": "a", "explanation": "Yes! The answer is \"more balanced, informed view\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A primary source is created by someone who:", "choices": [{"id": "a", "label": "wrote a later textbook"}, {"id": "b", "label": "invented a story"}, {"id": "c", "label": "studied an unrelated topic"}, {"id": "d", "label": "witnessed or took part in the event"}], "answer": "d", "explanation": "Yes! The answer is \"witnessed or took part in the event\"."}, {"type": "check", "title": "Your turn", "body": "Pick the best answer.", "prompt": "A secondary source typically:", "choices": [{"id": "a", "label": "analyzes or interprets events afterward"}, {"id": "b", "label": "is always firsthand"}, {"id": "c", "label": "is fiction"}, {"id": "d", "label": "contains no facts"}], "answer": "a", "explanation": "Yes! The answer is \"analyzes or interprets events afterward\"."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Analyzing Conflicting Sources! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
