update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Past-Tense Verbs", "body": "Past-tense verbs describe actions that already happened."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  What is the past tense of the verb \"think\"?\n\nThe answer is \"thought\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  What is the past tense of the verb \"know\"?\n\nThe answer is \"knew\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  What is the past tense of the verb \"buy\"?\n\nThe answer is \"bought\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  What is the past tense of the verb \"grow\"?\n\nThe answer is grew."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  What is the past tense of the verb \"draw\"?\n\nThe answer is drew."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  What is the past tense of the verb \"swim\"?\n\nThe answer is swam."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Past-Tense Verbs! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
where topic_id in (select t.id from public.topics t join public.subjects s on s.id = t.subject_id
  where s.slug = $tl$writing$tl$ and t.slug = $tl$past-tense-verbs$tl$ and t.grade_level = 8);

-- writing: Plural Nouns
update public.lessons set steps = $tl$[{"type": "explain", "title": "Let's learn: Plural Nouns", "body": "Plurals show more than one."}, {"type": "worked_example", "title": "Worked example 1", "body": "Example 1.  Write the plural of \"shelf\".\n\nThe answer is \"shelves\"."}, {"type": "worked_example", "title": "Worked example 2", "body": "Example 2.  Write the plural of \"loaf\".\n\nThe answer is \"loaves\"."}, {"type": "worked_example", "title": "Worked example 3", "body": "Example 3.  Write the plural of \"wish\".\n\nThe answer is \"wishes\"."}, {"type": "worked_example", "title": "Worked example 4", "body": "Example 4.  Write the plural of \"penny\".\n\nThe answer is pennies."}, {"type": "worked_example", "title": "Worked example 5", "body": "Example 5.  Write the plural of \"baby\".\n\nThe answer is babies."}, {"type": "worked_example", "title": "Worked example 6", "body": "Example 6.  Write the plural of \"half\".\n\nThe answer is halves."}, {"type": "explain", "title": "You've got this!", "body": "Great work learning about Plural Nouns! Now tap a worksheet to practice and earn points. You can always come back to this lesson."}]$tl$::jsonb
